    26	rrc_pdu_session_param_t *find_pduSession(gNB_RRC_UE_t *ue, int id, bool create)
    27	{
    28	  int j;
    29	  for (j = 0; j < ue->nb_of_pdusessions; j++)
    30	    if (id == ue->pduSession[j].param.pdusession_id)
    31	      break;
    32	  if (j == ue->nb_of_pdusessions) {
    33	    if (create)
    34	      ue->nb_of_pdusessions++;
    35	    else
    36	      return NULL;
    37	  }
    38	  return ue->pduSession + j;
    39	}
