    41	rrc_pdu_session_param_t *find_pduSession_from_drbId(gNB_RRC_UE_t *ue, int drb_id)
    42	{
    43	  const drb_t *drb = &ue->established_drbs[drb_id - 1];
    44	  if (drb->status == DRB_INACTIVE) {
    45	    LOG_E(NR_RRC, "UE %d: DRB %d inactive\n", ue->rrc_ue_id, drb_id);
    46	    return NULL;
    47	  }
    48	  int id = drb->cnAssociation.sdap_config.pdusession_id;
    49	  return find_pduSession(ue, id, false);
    50	}
