    52	drb_t *get_drb(gNB_RRC_UE_t *ue, uint8_t drb_id)
    53	{
    54	  DevAssert(drb_id > 0 && drb_id < 32);
    55	  DevAssert(ue != NULL);
    56	
    57	  return &ue->established_drbs[drb_id - 1];
    58	}
