   129	NR_DRB_ToAddMod_t *generateDRB_ASN1(const drb_t *drb_asn1)
   130	{
   131	  NR_DRB_ToAddMod_t *DRB_config = CALLOC(1, sizeof(*DRB_config));
   132	  NR_SDAP_Config_t *SDAP_config = CALLOC(1, sizeof(NR_SDAP_Config_t));
   133	
   134	  asn1cCalloc(DRB_config->cnAssociation, association);
   135	  asn1cCalloc(SDAP_config->mappedQoS_FlowsToAdd, sdapFlows);
   136	  asn1cCalloc(DRB_config->pdcp_Config, pdcpConfig);
   137	  asn1cCalloc(pdcpConfig->drb, drb);
   138	
   139	  DRB_config->drb_Identity = drb_asn1->drb_id;
   140	  association->present = drb_asn1->cnAssociation.present;
   141	
   142	  /* SDAP Configuration */
   143	  SDAP_config->pdu_Session = drb_asn1->cnAssociation.sdap_config.pdusession_id;
   144	  SDAP_config->sdap_HeaderDL = drb_asn1->cnAssociation.sdap_config.sdap_HeaderDL;
   145	  SDAP_config->sdap_HeaderUL = drb_asn1->cnAssociation.sdap_config.sdap_HeaderUL;
   146	  SDAP_config->defaultDRB = drb_asn1->cnAssociation.sdap_config.defaultDRB;
   147	
   148	  for (int qos_flow_index = 0; qos_flow_index < QOSFLOW_MAX_VALUE; qos_flow_index++) {
   149	    if (drb_asn1->cnAssociation.sdap_config.mappedQoS_FlowsToAdd[qos_flow_index] != 0) {
   150	      asn1cSequenceAdd(sdapFlows->list, NR_QFI_t, qfi);
   151	      *qfi = drb_asn1->cnAssociation.sdap_config.mappedQoS_FlowsToAdd[qos_flow_index];
   152	    }
   153	  }
   154	
   155	  association->choice.sdap_Config = SDAP_config;
   156	
   157	  /* PDCP Configuration */
   158	  asn1cCallocOne(drb->discardTimer, drb_asn1->pdcp_config.discardTimer);
   159	  asn1cCallocOne(drb->pdcp_SN_SizeUL, drb_asn1->pdcp_config.pdcp_SN_SizeUL);
   160	  asn1cCallocOne(drb->pdcp_SN_SizeDL, drb_asn1->pdcp_config.pdcp_SN_SizeDL);
   161	  asn1cCallocOne(pdcpConfig->t_Reordering, drb_asn1->pdcp_config.t_Reordering);
   162	
   163	  drb->headerCompression.present = drb_asn1->pdcp_config.headerCompression.present;
   164	  drb->headerCompression.choice.notUsed = drb_asn1->pdcp_config.headerCompression.NotUsed;
   165	
   166	  if (!drb_asn1->pdcp_config.integrityProtection) {
   167	    asn1cCallocOne(drb->integrityProtection, drb_asn1->pdcp_config.integrityProtection);
   168	  }
   169	  if (!drb_asn1->pdcp_config.ext1.cipheringDisabled) {
   170	    asn1cCalloc(pdcpConfig->ext1, ext1);
   171	    asn1cCallocOne(ext1->cipheringDisabled, drb_asn1->pdcp_config.ext1.cipheringDisabled);
   172	  }
   173	
   174	  return DRB_config;
   175	}
