   177	uint8_t get_next_available_drb_id(gNB_RRC_UE_t *ue)
   178	{
   179	  for (uint8_t drb_id = 0; drb_id < MAX_DRBS_PER_UE; drb_id++)
   180	    if (ue->established_drbs[drb_id].status == DRB_INACTIVE)
   181	      return drb_id + 1;
   182	  /* From this point, we need to handle the case that all DRBs are already used by the UE. */
   183	  LOG_E(RRC, "Error - All the DRBs are used - Handle this\n");
   184	  return DRB_INACTIVE;
   185	}
   186	
   187	bool drb_is_active(gNB_RRC_UE_t *ue, uint8_t drb_id)
   188	{
   189	  drb_t *drb = get_drb(ue, drb_id);
   190	  if (drb == NULL)
   191	    return DRB_INACTIVE;
   192	  return drb->status != DRB_INACTIVE;
   193	}

